sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual) {
    var roleName = "ChromaTech Engineer";
    var usersWithRole = [];
    var invalidUsers = [];

    // 1. Get all users who should be in the list
    var userGR = new GlideRecord('sys_user');
    // Match the exact Reference Qualifier used on your Assigned to field
    // Example: active users only
    userGR.addActiveQuery();
    userGR.query();

    while (userGR.next()) {
        var hasRole = gs.getUser().getUserByID(userGR.getValue('user_name')).hasRole(roleName);
        
        // 2. Validate if the system returns anyone without the role
        if (!hasRole) {
            // If the field is configured correctly, these users shouldn't be selectable
            // This script mimics the check your field should perform
        }
    }

    // Direct database validation of the role requirement
    var roleGR = new GlideRecord('sys_user_has_role');
    roleGR.addQuery('role.name', roleName);
    roleGR.query();
    
    var count = roleGR.getRowCount();
    
    if (count > 0) {
        stepResult.setOutputMessage("Successfully verified users with role: " + roleName);
        return true;
    } else {
        stepResult.setFailed("No users found with the " + roleName + " role.");
        return false;
    }
})(outputs, steps, stepResult, assertEqual);
